\documentclass[10pt]{article}
\usepackage[utf8]{inputenc}
\usepackage[T1]{fontenc}
\usepackage[czech]{babel}
\usepackage{geometry}
\usepackage{xcolor}
\usepackage{tcolorbox}
\usepackage{tikz}
\usepackage{enumitem}

% Okraje pro A4
\geometry{a4paper, margin=2cm}

% Barvy
\definecolor{zfblue}{HTML}{2A6DAB}
\definecolor{zfpurple}{HTML}{6A3AA0}
\definecolor{zfred}{HTML}{B54530}
\definecolor{zfgray}{HTML}{FAFAFA}

\setlist[itemize]{noitemsep, topsep=2pt, leftmargin=18pt}

\begin{document}
\pagestyle{empty}

\begin{flushleft}
    {\LARGE \bfseries Teplota} \\[2mm]
    {\color{zfblue}\hrule height 1.5pt}
    \vspace{4mm}

    \begin{itemize}
        \item Značka: \textbf{t}
        \item Základní jednotka: \textbf{$^\circ$C} (stupeň Celsia)
        \item Další jednotky: \textbf{K} (kelvin), \textbf{$^\circ$F} (stupeň Fahrenheita)
    \end{itemize}

    \vspace{6mm}
    {\Large \bfseries \color{zfblue} Teplotní stupnice}
    \vspace{2mm}

    \begin{tcolorbox}[colback=zfgray, colframe=zfblue, title=Celsiova, fonttitle=\bfseries, boxrule=0.5pt, leftrule=0pt, rightrule=0pt, bottomrule=0pt, toprule=3pt, arc=2pt, left=4pt, right=4pt, top=2pt, bottom=2pt, coltitle=black, attach title to upper]
        \begin{itemize}
            \item Anders Celsius (1742)
            \item 0 $^\circ$C -- tání ledu; 100 $^\circ$C -- var vody
            \item Používá se v Evropě
        \end{itemize}
    \end{tcolorbox}

    \begin{tcolorbox}[colback=zfgray, colframe=zfpurple, title=Termodynamická (Kelvinova), fonttitle=\bfseries, boxrule=0.5pt, leftrule=0pt, rightrule=0pt, bottomrule=0pt, toprule=3pt, arc=2pt, left=4pt, right=4pt, top=2pt, bottom=2pt, coltitle=black, attach title to upper]
        \begin{itemize}
            \item Lord Kelvin (1848)
            \item Začíná od abs. nuly, nemá záporné teploty
            \item Využití ve fyzice
        \end{itemize}
    \end{tcolorbox}

    \begin{tcolorbox}[colback=zfgray, colframe=zfred, title=Fahrenheitova, fonttitle=\bfseries, boxrule=0.5pt, leftrule=0pt, rightrule=0pt, bottomrule=0pt, toprule=3pt, arc=2pt, left=4pt, right=4pt, top=2pt, bottom=2pt, coltitle=black, attach title to upper]
        \begin{itemize}
            \item D. G. Fahrenheit (1724)
            \item 0 $^\circ$F -- směs ledu a salmiaku; 96 $^\circ$F -- teplota lidského těla
            \item Používá se v USA
        \end{itemize}
    \end{tcolorbox}

    \vspace{8mm}
    {\Large \bfseries \color{zfblue} Porovnání tří stupnic}
    \vspace{4mm}

    \begin{center}
    \begin{tikzpicture}[scale=1.2, every node/.style={font=\normalsize}]
        \draw[dashed, gray!40] (0, 0) -- (0, -4.5) node[above at start, black] {Absolutní nula};
        \draw[dashed, gray!40] (5, 0) -- (5, -4.5) node[above at start, black] {Tání ledu};
        \draw[dashed, gray!40] (7.5, 0) -- (7.5, -4.5) node[above at start, black] {Var vody};

        \filldraw[fill=zfblue!10, draw=zfblue, thick, rounded corners=2pt] (-1.2, -0.2) rectangle (8.4, -1.1);
        \node[left, zfblue, font=\normalsize\bfseries] at (-1.2, -0.65) {Celsiova};
        \node at (0, -0.65) {$-273^\circ$C}; \node at (5, -0.65) {$0^\circ$C}; \node at (7.5, -0.65) {$100^\circ$C};

        \filldraw[fill=zfpurple!10, draw=zfpurple, thick, rounded corners=2pt] (-1.2, -1.6) rectangle (8.4, -2.5);
        \node[left, zfpurple, font=\normalsize\bfseries] at (-1.2, -2.05) {Kelvinova};
        \node at (0, -2.05) {$0$ K}; \node at (5, -2.05) {$273$ K}; \node at (7.5, -2.05) {$373$ K};

        \filldraw[fill=zfred!10, draw=zfred, thick, rounded corners=2pt] (-1.2, -3.0) rectangle (8.4, -3.9);
        \node[left, zfred, font=\normalsize\bfseries] at (-1.2, -3.45) {Fahrenheit.};
        \node at (0, -3.45) {$-460^\circ$F}; \node at (5, -3.45) {$32^\circ$F}; \node at (7.5, -3.45) {$212^\circ$F};
    \end{tikzpicture}
    \end{center}

    \vspace{8mm}
    {\Large \bfseries \color{zfblue} Absolutní nula}
    \begin{itemize}
        \item Nejnižší možná teplota ve vesmíru ($0$ K = $-273{,}15\,^\circ$C).
        \item Částice se v ní téměř nepohybují.
    \end{itemize}

    \vspace{6mm}
    {\Large \bfseries \color{zfblue} Druhy teploměrů}
    \begin{itemize}
        \item \textbf{Kapalinový} (rtuť/líh) -- kapalina se roztahuje teplem.
        \item \textbf{Bimetalový} -- dva kovy, ohýbání teplem.
        \item \textbf{Digitální} -- elektronické čidlo, čteme na displeji.
        \item \textbf{Bezdotykový} -- měří tepelné záření na dálku.
    \end{itemize}
\end{flushleft}

\end{document}
